const addItem = p => {
    setItems(prev => {
      const existing = prev.find(i => i.id === p.id);
      if (existing) {
        if (existing.qty >= p.stock_quantity) { toast.error('Not enough stock'); return prev; }
        return prev.map(i => i.id === p.id ? { ...i, qty: i.qty + 1 } : i);
      }
      return [...prev, {
        id:           p.id,
        name:         p.name,
        barcode:      p.barcode,
        price:        parseFloat(p.selling_price),
        qty:          1,
        stock:        parseFloat(p.stock_quantity),
        selling_unit: p.selling_unit || 'nos',
      }];
    });
  };
